<!DOCTYPE html>
<html lang="en">

<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Welcome to SIPRESTA</title>
    @vite(['resources/css/app.css'])
    @googlefonts('poppins')
</head>

<body class="max-h-250 bg-gradient-to-b from-[#0c2c48] to-[#1e6aae] bg-no-repeat font-poppins overflow-x-hidden">
    <div class="w-4/5 h-full mx-auto">
        <!-- Header -->
        <header class="text-white p-4 flex justify-between items-center">
            <img src="{{ asset('images/Logo.svg') }}" alt="" class="w-[12%] h-[12%]">
            <div class="flex space-x-14 text-xs uppercase tracking-widest">
                <a href="" class="hover:underline hover:underline-offset-4 hover:decoration-2 hover:decoration-white hover:scale-110 transition duration-300 ease-in-out">
                    <p>Fitur</p>
                </a>
                <a href="" class="hover:underline hover:underline-offset-4 hover:decoration-2 hover:decoration-white hover:scale-110 transition duration-300 ease-in-out">
                    <p>Product</p>
                </a>
                <a href="" class="hover:underline hover:underline-offset-4 hover:decoration-2 hover:decoration-white hover:scale-110 transition duration-300 ease-in-out">
                    <p>Lorem</p>
                </a>
                <a href="" class="hover:underline hover:underline-offset-4 hover:decoration-2 hover:decoration-white hover:scale-110 transition duration-300 ease-in-out">
                    <p>About Us</p>
                </a>
                <a href="" class="hover:underline hover:underline-offset-4 hover:decoration-2 hover:decoration-white hover:scale-110 transition duration-300 ease-in-out">
                    <p>Ipsum</p>
                </a>
                <a href="" class="hover:underline hover:underline-offset-4 hover:decoration-2 hover:decoration-white hover:scale-110 transition duration-300 ease-in-out">
                    <p>Campaigns</p>
                </a>
            </div>
            <a href="" class="flex items-center bg-gray-100 text-indigo-950 px-8 py-2 rounded-sm hover:bg-[var(--color-primary)] hover:text-white hover:scale-110 transition duration-300 ease-in-out ">
                <p class="font-semibold">Login</p>
            </a>
        </header>
    </div>

    <!-- Catat Prestasi -->
    <main class="w-4/5 mx-auto">
        <div class="flex flex-row mb-0">
            <section class="flex flex-col items-start justify-start h-full text-white mt-25 space-y-2 mb-50">
                <h1 class="text-6xl font-semibold">Catat Prestasi.</h1>
                <h1 class="text-6xl font-medium">Temukan Peluang.</h1>
                <h1 class="text-6xl font-medium">Raih Masa Depan.</h1>

                <!-- Subtitle -->
                <p class="text-lg mt-4 w-130">Platform cerdas untuk pencatatan prestasi mahasiswa dan rekomendasi peserta lomba di JTI Polinema.</p>
                <!-- Button Lihat Fitur & Mulai Sekarang -->
                <div class="mt-8 flex flex-row space-x-4 uppercase tracking-wide">
                    <a href="" class="bg-gray-100 text-indigo-950 px-10 py-4 rounded-sm font-semibold">
                        Lihat Fitur
                    </a>
                    <a href="" class="flex flex-row outline-2 text-gray-100 px-10 py-4 rounded-sm font-semibold">
                        <span class="mr-2">Mulai Sekarang</span>
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="2" stroke="currentColor" class="size-6">
                            <path stroke-linecap="round" stroke-linejoin="round" d="m4.5 19.5 15-15m0 0H8.25m11.25 0v11.25" />
                        </svg>
                    </a>
                </div>

            </section>
            <!-- image -->
            <div class="absolute right-10 top-30 scale-90 pointer-events-none">
                <img src="{{ asset('images/head-image.svg') }}" alt="" class="w-full h-full object-cover">
            </div>
        </div>
    </main>

    <!-- Reason -->
    <section class="w-4/5 mx-auto flex flex-col relative py-20 px-25 bg-gray-50 shadow-2xl rounded-3xl">
        <h2 class="text-xl font-bold text-sky-600 pb-3 uppercase">Reason</h2>
        <div class="flex flex-row space-x-20">
            <h1 class="text-4xl font-bold w-[100%] text-indigo-950">Kenapa Sistem Ini Diperlukan?</h1>
            <p class="text-indigo-950">Mahasiswa JTI Polinema terus menorehkan prestasi gemilang di berbagai kompetisi teknologi informasi dan sistem informasi seperti:</p>
        </div>
        <div class="flex flex-row space-x-20 mt-20 text-center font-bold">
            <div class="flex flex-col justify-between">
                <p class="text-indigo-950">Gemastik</p>
                <hr class="border-3 border-indigo-700 w-full items-end rounded">
            </div>
            <div class="flex flex-col justify-between">
                <p class="text-indigo-950">Hacketon</p>
                <hr class="border-3 border-indigo-700 w-full mt-2 rounded">
            </div>
            <div class="flex flex-col justify-between">
                <p class="text-indigo-950">Lomba Desain UI/UX</p>
                <hr class="border-3 border-indigo-700 w-full mt-2 rounded">
            </div>
            <div class="flex flex-col justify-between">
                <Io class="text-indigo-950">Kompetisi IoT</p>
                    <hr class="border-3 border-indigo-700 w-full mt-2 rounded">
            </div>
            <div class="flex flex-col justify-between">
                <p class="text-indigo-950">Kompetisi Keamanan Siber</p>
                <hr class="border-3 border-indigo-700 w-full mt-2 rounded">
            </div>
        </div>
    </section>


    <section class="w-4/5 mx-auto flex flex-col relative py-20 px-25 align-content-center">
        <div class="flex flex-col text-center items-center justify-center">
            <h3>Namun, proses memilih peserta lomba yang tepat masih menghadapi tantangan:</h3>
            <h3 class="font-semibold text-gray-50 bg-indigo-700 w-fit py-1 px-3 mt-4">Bagaimana memastikan setiap lomba diikuti oleh mahasiswa yang paling sesuai?</h3>
        </div>
    </section>

    <section class="w-4/5 mx-auto">
        <div class="flex flex-col text-center items-center justify-center mt-20">
            <h2 class="uppercase text-sm font-bold">Our Solution</h2>
            <h1>Solusi Cerdas untuk Prestasi Lebih Gemilang</h1>
        </div>

        <div class="flex flex-col text-center items-center justify-center mt-20">
            <img src="{{ asset('images/Logo-Blue.svg') }}" alt="">
            <div class="flex flex-row space-x-20 mt-10">
                <div class="flex flex-col w-2/4 items-start bg-indigo-100 rounded-2xl p-10 shadow-sm">
